const response = $json;
const trigger = $('Webhook Trigger').item.json.body;

if (response.commit?.sha) {
  return [{ json: {
    erfolg: true,
    datei: trigger.path,
    commit_sha: response.commit.sha,
    commit_url: response.commit.html_url ?? '',
    nachricht: '✅ ' + trigger.path + ' erfolgreich nach GitHub gepusht.'
  }}];
}

return [{ json: {
  erfolg: false,
  fehler: response.message ?? JSON.stringify(response),
  nachricht: '❌ Push fehlgeschlagen: ' + (response.message ?? 'Unbekannter Fehler')
}}];

const trig = $('Webhook Trigger').first().json.body;
const shaResponse = $input.first().json;

// Content robust als Base64 kodieren (btoa versagt bei UTF-8)
const rawContent = trig.content || '';
const contentBase64 = Buffer.from(rawContent, 'utf-8').toString('base64');

// GitHub API Body zusammenbauen
const payload = {
  message: trig.message || 'chore: update via Claude',
  content: contentBase64,
  branch: trig.branch || 'main'
};

// SHA nur hinzufügen wenn Datei bereits existiert (kein 404)
if (shaResponse.sha) {
  payload.sha = shaResponse.sha;
}

return [{
  json: {
    body: payload,
    owner: trig.owner || 'peerendees',
    repo: trig.repo || 'n8n-workflows',
    path: trig.path
  }
}];
